sys_variable_value.value:
(function execute(inputs, outputs) {

    var response = JSON.parse(inputs.response);
    var inputEmail = (inputs.email || '').toLowerCase();

    outputs.user_xero_id = 'false';

    if (response.Users && response.Users.length > 0) {
        for (var i = 0; i < response.Users.length; i++) {
            var user = response.Users[i];

            if ((user.EmailAddress || '').toLowerCase() === inputEmail) {
                outputs.user_xero_id = user.GlobalUserID || user.UserID;
                break;
            }
        }
    }

})(inputs, outputs);

